import re, sys

# Minimal TOML parser (key = "value" and [section] / [section.sub] only)
def parse_toml_simple(text):
    """Returns a nested dict for the small, flat TOML files we have here."""
    result = {}
    current = result
    path = []

    for raw in text.splitlines():
        line = raw.strip()
        if not line or line.startswith('#'):
            continue
        # Section header
        if line.startswith('['):
            header = line.strip('[]').strip()
            parts = [p.strip() for p in header.split('.')]
            path = parts
            node = result
            for p in parts:
                node = node.setdefault(p, {})
            current = node
            continue
        # Key = value
        if '=' in line:
            k, _, v = line.partition('=')
            k = k.strip()
            v = v.strip()
            # string
            if v.startswith('"') and v.endswith('"'):
                v = v[1:-1]
            # integer
            elif v.lstrip('-').isdigit():
                v = int(v)
            # boolean
            elif v in ('true', 'false'):
                v = v == 'true'
            current[k] = v

    return result

